import { SeedSubsection } from '../seed'

export const subsectionsPart3: SeedSubsection[] = [
  // === DOMAIN 11: COSMOLOGY - Origin of the Universe ===
  { id: 'sub-big-bang-1', entryId: 'entry-big-bang-theory', title_es: 'Evidencia observacional', title_en: 'Observational evidence',
    content_es: 'El Big Bang está respaldado por múltiples líneas de evidencia independientes. La expansión del universo se observa mediante el corrimiento al rojo de galaxias lejanas, descubierto por Edwin Hubble en 1929. La radiación cósmica de fondo de microondas, detectada por primera vez en 1965, es la luz más antigua del universo, emitida 380,000 años después del Big Bang. La abundancia de elementos ligeros coincide con las predicciones de la nucleosíntesis primordial.',
    content_en: 'The Big Bang is supported by multiple independent lines of evidence. Universal expansion is observed through the redshift of distant galaxies, discovered by Edwin Hubble in 1929. The cosmic microwave background radiation, first detected in 1965, is the oldest light in the universe, emitted 380,000 years after the Big Bang. The abundance of light elements matches predictions from primordial nucleosynthesis.',
    order: 0 },
  { id: 'sub-big-bang-2', entryId: 'entry-big-bang-theory', title_es: 'Limitaciones del modelo', title_en: 'Model limitations',
    content_es: 'El Big Bang describe la evolución del universo desde sus primeros instantes pero no explica la singularidad inicial ni qué ocurrió antes. Las leyes de la física se rompen en ese punto. La cosmología inflacionaria, la gravedad cuántica de bucles y la teoría de cuerdas intentan abordar estas preguntas fundamentales. El telescopio James Webb continúa desafiando y refinando el modelo al observar galaxias sorprendentemente maduras en el universo temprano.',
    content_en: 'The Big Bang describes universal evolution from its earliest instants but does not explain the initial singularity or what happened before. The laws of physics break down at that point. Inflationary cosmology, loop quantum gravity, and string theory attempt to address these fundamental questions. The James Webb telescope continues challenging and refining the model by observing surprisingly mature galaxies in the early universe.',
    order: 1 },
  { id: 'sub-infl-1', entryId: 'entry-inflation', title_es: 'Problemas resueltos', title_en: 'Problems solved',
    content_es: 'La inflación cósmica resuelve tres problemas fundamentales del Big Bang clásico. El problema del horizonte: regiones opuestas del universo tienen la misma temperatura sin haber estado en contacto, imposible en un modelo de expansión lineal. La inflación explica que todo el universo observable estuvo en equilibrio térmico antes de expandirse exponencialmente. El problema de la planitud explica por qué la curvatura del universo es casi perfectamente plana. El problema de los monopolos explica la ausencia de estas partículas predichas por las teorías de gran unificación.',
    content_en: 'Cosmic inflation solves three fundamental problems of the classical Big Bang. The horizon problem: opposite regions of the universe have the same temperature without having been in contact, impossible in a linear expansion model. Inflation explains that the entire observable universe was in thermal equilibrium before expanding exponentially. The flatness problem explains why the universe\'s curvature is nearly perfectly flat. The monopole problem explains the absence of these particles predicted by grand unified theories.',
    order: 0 },
  { id: 'sub-infl-2', entryId: 'entry-inflation', title_es: 'Inflación eterna', title_en: 'Eternal inflation',
    content_es: 'La inflación eterna, propuesta por Alexander Vilenkin y Andrei Linde, sugiere que la inflación no termina en todo el espacio simultáneamente. En algunas regiones, la inflación continúa mientras otras forman "universos burbuja" que se convierten en dominios como nuestro universo observable. Esto implica un multiverso de burbujas infinitas, cada una potencialmente con diferentes leyes físicas. Esta teoría es especulativa y difícil de probar.',
    content_en: 'Eternal inflation, proposed by Alexander Vilenkin and Andrei Linde, suggests inflation does not end everywhere simultaneously. In some regions, inflation continues while others form "bubble universes" that become domains like our observable universe. This implies an infinite multiverse of bubbles, each potentially with different physical laws. This theory is speculative and difficult to prove.',
    order: 1 },
  { id: 'sub-mult-1', entryId: 'entry-multiverse', title_es: 'Tipos de multiverso', title_en: 'Types of multiverse',
    content_es: 'Max Tegmark propuso una clasificación cuádruple. Tipo I: regiones más allá del horizonte cósmico observable, con las mismas leyes físicas pero diferentes condiciones iniciales. Tipo II: universos burbuja generados por inflación caótica eterna, potencialmente con diferentes constantes físicas. Tipo III: el multiverso de la interpretación de muchos mundos de la mecánica cuántica. Tipo IV: universos con estructuras matemáticas radicalmente diferentes.',
    content_en: 'Max Tegmark proposed a four-level classification. Type I: regions beyond the observable cosmic horizon, with the same physical laws but different initial conditions. Type II: bubble universes generated by eternal chaotic inflation, potentially with different physical constants. Type III: the multiverse of the many-worlds interpretation of quantum mechanics. Type IV: universes with radically different mathematical structures.',
    order: 0 },
  { id: 'sub-mult-2', entryId: 'entry-multiverse', title_es: 'Crítica y debate', title_en: 'Critique and debate',
    content_es: 'La hipótesis del multiverso es controvertida por su falta de falsabilidad. Críticos como Paul Steinhardt y George Ellis argumentan que no es ciencia sino filosofía. Sin embargo, algunos defensores señalan que ciertos multiversos (Tipo I) son consecuencias inevitables de la inflación y la mecánica cuántica. La detección de patrones anómalos en la radiación cósmica de fondo podría proporcionar evidencia indirecta de colisiones entre universos burbuja.',
    content_en: 'The multiverse hypothesis is controversial due to its lack of falsifiability. Critics like Paul Steinhardt and George Ellis argue it is not science but philosophy. However, some defenders note that certain multiverses (Type I) are inevitable consequences of inflation and quantum mechanics. Detection of anomalous patterns in the cosmic microwave background could provide indirect evidence of collisions between bubble universes.',
    order: 1 },
  { id: 'sub-dark-1', entryId: 'entry-dark-matter-energy', title_es: 'Evidencia de materia oscura', title_en: 'Dark matter evidence',
    content_es: 'La evidencia más convincente proviene de las curvas de rotación galáctica. Según la física newtoniana, las estrellas en los bordes galácticos deberían orbitar más lentamente que las cercanas al centro, pero las observaciones muestran velocidades casi constantes. Esto implica masa invisible adicional. Otras evidencias incluyen lentes gravitacionales en cúmulos de galaxias, la estructura a gran escala del universo y las mediciones del fondo cósmico de microondas.',
    content_en: 'The most compelling evidence comes from galactic rotation curves. According to Newtonian physics, stars at galactic edges should orbit slower than those near the center, but observations show nearly constant velocities. This implies additional invisible mass. Other evidence includes gravitational lensing in galaxy clusters, the large-scale structure of the universe, and cosmic microwave background measurements.',
    order: 0 },
  { id: 'sub-dark-2', entryId: 'entry-dark-matter-energy', title_es: 'Candidatos y experimentos', title_en: 'Candidates and experiments',
    content_es: 'Los principales candidatos para materia oscura son las WIMPs (partículas masivas de interacción débil) y los axiones. Experimentos subterráneos como LUX, XENON1T y PandaX buscan detectar WIMPs sin éxito hasta ahora. El LHC también busca evidencia de supersimetría, que podría proporcionar candidatos. Para la energía oscura, los telescopios Euclid, DESI y el Observatorio Vera Rubin cartografiarán la expansión cósmica para determinar si la energía oscura es constante o variable en el tiempo.',
    content_en: 'Main candidates for dark matter are WIMPs (Weakly Interacting Massive Particles) and axions. Underground experiments like LUX, XENON1T, and PandaX search for WIMPs without success so far. The LHC also searches for evidence of supersymmetry, which could provide candidates. For dark energy, the Euclid, DESI, and Vera Rubin Observatory telescopes will map cosmic expansion to determine whether dark energy is constant or varies over time.',
    order: 1 },

  // === DOMAIN 11: COSMOLOGY - Origin of Life ===
  { id: 'sub-abio-1', entryId: 'entry-abiogenesis', title_es: 'El experimento de Miller-Urey', title_en: 'The Miller-Urey experiment',
    content_es: 'En 1953, Stanley Miller y Harold Urey simularon las condiciones de la Tierra primitiva en su laboratorio. Usaron una mezcla de agua, metano, amoníaco e hidrógeno, y aplicaron descargas eléctricas para simular rayos. Tras una semana, encontraron que se habían formado aminoácidos, los bloques fundamentales de las proteínas. Experimentos posteriores con diferentes composiciones atmosféricas han producido una amplia variedad de moléculas orgánicas, incluyendo nucleótidos y lípidos simples.',
    content_en: 'In 1953, Stanley Miller and Harold Urey simulated early Earth conditions in their laboratory. They used a mixture of water, methane, ammonia, and hydrogen, applying electrical discharges to simulate lightning. After a week, they found that amino acids had formed, the fundamental building blocks of proteins. Subsequent experiments with different atmospheric compositions have produced a wide variety of organic molecules, including nucleotides and simple lipids.',
    order: 0 },
  { id: 'sub-abio-2', entryId: 'entry-abiogenesis', title_es: 'Desafíos pendientes', title_en: 'Remaining challenges',
    content_es: 'Aunque la formación de moléculas orgánicas está bien documentada, el salto a la primera célula autorreplicante sigue sin resolverse. Los desafíos incluyen cómo se formaron las membranas celulares, cómo surgió la replicación fiel de información genética, y cómo se estableció el código genético universal. Las investigaciones actuales exploran la evolución de protocélulas en laboratorio y la química prebiótica en ambientes simulados.',
    content_en: 'Although the formation of organic molecules is well documented, the leap to the first self-replicating cell remains unsolved. Challenges include how cell membranes formed, how faithful replication of genetic information emerged, and how the universal genetic code was established. Current research explores the evolution of protocells in the laboratory and prebiotic chemistry in simulated environments.',
    order: 1 },
  { id: 'sub-rna-1', entryId: 'entry-rna-world', title_es: 'Ribozimas y catálisis', title_en: 'Ribozymes and catalysis',
    content_es: 'Antes del ADN y las proteínas, el ARN pudo haber sido la molécula central de la vida. Los ribozimas son moléculas de ARN con actividad catalítica, descubiertas por Thomas Cech y Sidney Altman en la década de 1980. Pueden catalizar su propio corte y empalme, demostrando que el ARN puede almacenar información y acelerar reacciones químicas. Esto sugiere que un "mundo de ARN" primitivo pudo existir antes de la evolución del ADN y las proteínas.',
    content_en: 'Before DNA and proteins, RNA may have been the central molecule of life. Ribozymes are RNA molecules with catalytic activity, discovered by Thomas Cech and Sidney Altman in the 1980s. They can catalyze their own splicing, demonstrating that RNA can both store information and accelerate chemical reactions. This suggests a primitive "RNA world" may have existed before the evolution of DNA and proteins.',
    order: 0 },
  { id: 'sub-rna-2', entryId: 'entry-rna-world', title_es: 'Huellas en la biología moderna', title_en: 'Traces in modern biology',
    content_es: 'La biología moderna conserva vestigios del mundo de ARN. Los ribosomas, que sintetizan proteínas en todas las células, son esencialmente ribozimas: su centro catalítico está compuesto de ARN, no de proteínas. Los nucleótidos de ARN son precursores metabólicos fundamentales. La coenzima NAD y el ATP son derivados de nucleótidos. Estas huellas moleculares sugieren que el mundo de ARN precedió y sentó las bases del mundo de ADN y proteínas.',
    content_en: 'Modern biology retains vestiges of the RNA world. Ribosomes, which synthesize proteins in all cells, are essentially ribozymes: their catalytic core is composed of RNA, not proteins. RNA nucleotides are fundamental metabolic precursors. The coenzyme NAD and ATP are nucleotide derivatives. These molecular traces suggest the RNA world preceded and laid the groundwork for the DNA and protein world.',
    order: 1 },
  { id: 'sub-pans-1', entryId: 'entry-panspermia', title_es: 'Supervivencia interestelar', title_en: 'Interstellar survival',
    content_es: 'Experimentos en la Estación Espacial Internacional han demostrado que organismos extremófilos como tardígrados, bacterias y líquenes pueden sobrevivir años de exposición al espacio abierto. Las bacterias pueden sobrevivir atrapadas en sales dentro de meteoritos. El experimento EXPOSE en la ISS confirmó que Bacillus subtilis puede resistir radiación UV extrema cuando está protegido por capas de polvo o roca.',
    content_en: 'Experiments on the International Space Station have shown that extremophile organisms like tardigrades, bacteria, and lichens can survive years of open space exposure. Bacteria can survive trapped in salts inside meteorites. The EXPOSE experiment on the ISS confirmed that Bacillus subtilis can withstand extreme UV radiation when protected by dust or rock layers.',
    order: 0 },
  { id: 'sub-pans-2', entryId: 'entry-panspermia', title_es: 'Litopanspermia marciana', title_en: 'Martian lithopanspermia',
    content_es: 'Se han encontrado meteoritos en la Tierra que provienen de Marte, eyectados por impactos de asteroides. El famoso ALH84001 causó controversia en 1996 cuando científicos de la NASA anunciaron haber encontrado posibles microfósiles bacterianos en su interior. Aunque la hipótesis de vida marciana en este meteorito no fue confirmada, demostró que el intercambio de material rocoso entre planetas es un hecho, no una especulación.',
    content_en: 'Meteorites found on Earth come from Mars, ejected by asteroid impacts. The famous ALH84001 caused controversy in 1996 when NASA scientists announced finding possible bacterial microfossils inside. Although the hypothesis of Martian life in this meteorite was not confirmed, it demonstrated that rocky material exchange between planets is a fact, not speculation.',
    order: 1 },
  { id: 'sub-hydro-1', entryId: 'entry-hydrothermal-vent', title_es: 'Fumarolas negras', title_en: 'Black smokers',
    content_es: 'Descubiertas en 1977 en la dorsal de Galápagos, las fumarolas negras emiten agua supercaliente a más de 350°C, rica en sulfuros metálicos. Al contacto con el agua fría (2°C), los minerales precipitan formando chimeneas de hasta 60 metros. Estos ecosistemas albergan bacterias quimiosintéticas que obtienen energía de compuestos inorgánicos, formando la base de una cadena alimenticia independiente de la luz solar.',
    content_en: 'Discovered in 1977 on the Galápagos Rift, black smokers emit superheated water at over 350°C, rich in metallic sulfides. Upon contact with cold water (2°C), minerals precipitate forming chimneys up to 60 meters tall. These ecosystems host chemosynthetic bacteria that obtain energy from inorganic compounds, forming the base of a food chain independent of sunlight.',
    order: 0 },
  { id: 'sub-hydro-2', entryId: 'entry-hydrothermal-vent', title_es: 'Gradiente químico como motor', title_en: 'Chemical gradient as engine',
    content_es: 'Las fumarolas hidrotermales generan gradientes químicos y térmicos extremos. La teoría propone que estos gradientes proporcionaron la energía necesaria para la síntesis de moléculas orgánicas complejas. Los poros de las chimeneas minerales actuaron como compartimentos naturales que concentraban moléculas. El descubrimiento de que las ATPasas celulares funcionan mediante gradientes de protones —exactamente como ocurre en las fumarolas— sugiere que la vida aprovechó estos gradientes naturales desde su origen.',
    content_en: 'Hydrothermal vents generate extreme chemical and thermal gradients. The theory proposes these gradients provided the energy necessary for the synthesis of complex organic molecules. The pores of mineral chimneys acted as natural compartments concentrating molecules. The discovery that cellular ATPases function through proton gradients — exactly as occurs at vents — suggests life harnessed these natural gradients from its origin.',
    order: 1 },

  // === DOMAIN 11: COSMOLOGY - Origin of Humankind ===
  { id: 'sub-oaf-1', entryId: 'entry-out-of-africa', title_es: 'Evidencia fósil', title_en: 'Fossil evidence',
    content_es: 'Los fósiles más antiguos de Homo sapiens se encuentran en África. Jebel Irhoud (Marruecos) data de hace unos 315,000 años. Omo Kibish (Etiopía) tiene 195,000 años. Herto Bouri (Etiopía) unos 160,000 años. Estos fósiles muestran una mezcla de rasgos modernos y arcaicos, documentando la evolución gradual de nuestra especie. Los fósiles fuera de África son más recientes: los primeros sapiens en Europa tienen unos 45,000 años, y en América unos 15,000 años.',
    content_en: 'The oldest Homo sapiens fossils are found in Africa. Jebel Irhoud (Morocco) dates to about 315,000 years ago. Omo Kibish (Ethiopia) is 195,000 years old. Herto Bouri (Ethiopia) around 160,000 years. These fossils show a mix of modern and archaic features, documenting the gradual evolution of our species. Fossils outside Africa are younger: the first sapiens in Europe are about 45,000 years old, and in the Americas about 15,000 years.',
    order: 0 },
  { id: 'sub-oaf-2', entryId: 'entry-out-of-africa', title_es: 'Rutas migratorias', title_en: 'Migration routes',
    content_es: 'La migración fuera de África ocurrió en múltiples oleadas. La más significativa hace 60,000-70,000 años, siguiendo la ruta costera del sur de Asia. Los sapiens llegaron a Australia hace unos 65,000 años. Europa fue colonizada desde el sureste hace unos 45,000 años. Siberia y el norte de Asia fueron poblados después, y desde allí cruzaron el puente de Beringia hacia América hace al menos 15,000 años. Los cambios climáticos y los niveles del mar influyeron en estas rutas.',
    content_en: 'Migration out of Africa occurred in multiple waves. The most significant was 60,000-70,000 years ago, following the southern Asian coastal route. Sapiens reached Australia about 65,000 years ago. Europe was colonized from the southeast about 45,000 years ago. Siberia and northern Asia were populated later, and from there they crossed the Beringia land bridge to the Americas at least 15,000 years ago. Climate changes and sea levels influenced these routes.',
    order: 1 },
  { id: 'sub-mreg-1', entryId: 'entry-multiregional', title_es: 'Origen del modelo', title_en: 'Origin of the model',
    content_es: 'La hipótesis multirregional fue desarrollada por Milford Wolpoff en la década de 1980 como alternativa al modelo Out of Africa. Se basa en la observación de cierta continuidad morfológica en el registro fósil de regiones como China (rasgos faciales) e Indonesia (forma del cráneo). Propone que Homo erectus se dispersó desde África hace 1.8 millones de años y las poblaciones regionales evolucionaron en paralelo hacia Homo sapiens, conectadas por flujo genético.',
    content_en: 'The multiregional hypothesis was developed by Milford Wolpoff in the 1980s as an alternative to the Out of Africa model. It is based on the observation of certain morphological continuity in the fossil record from regions such as China (facial features) and Indonesia (skull shape). It proposes that Homo erectus dispersed from Africa 1.8 million years ago and regional populations evolved in parallel toward Homo sapiens, connected by gene flow.',
    order: 0 },
  { id: 'sub-mreg-2', entryId: 'entry-multiregional', title_es: 'Estado actual', title_en: 'Current status',
    content_es: 'La evidencia genética moderna ha refutado el multirregionalismo clásico. El ADN mitocondrial, el cromosoma Y y los genomas nucleares completos confirman un origen africano reciente para todos los humanos modernos. Sin embargo, en versión revisada, el modelo acepta hibridación limitada con poblaciones arcaicas locales. Hoy sabemos que los europeos y asiáticos tienen 1-4% de ADN neandertal, y los oceánicos hasta 5% de ADN denisovano, sugiriendo que hubo contribuciones arcaicas menores.',
    content_en: 'Modern genetic evidence has refuted classical multiregionalism. Mitochondrial DNA, the Y chromosome, and complete nuclear genomes confirm a recent African origin for all modern humans. However, in a revised version, the model accepts limited hybridization with local archaic populations. Today we know Europeans and Asians have 1-4% Neanderthal DNA, and Oceanians up to 5% Denisovan DNA, suggesting minor archaic contributions existed.',
    order: 1 },
  { id: 'sub-nean-1', entryId: 'entry-neanderthal-dna', title_es: 'El genoma neandertal', title_en: 'The Neanderthal genome',
    content_es: 'Svante Pääbo logró lo que parecía imposible: secuenciar el genoma completo de una especie extinta. Su equipo extrajo ADN de huesos neandertales de 40,000 años de antigüedad, desarrollando técnicas pioneras para evitar la contaminación con ADN humano moderno. En 2010 publicaron el primer borrador del genoma neandertal. La comparación con genomas humanos modernos reveló que los no africanos comparten un 1-4% de su ADN con neandertales. Pääbo recibió el Premio Nobel de Medicina en 2022.',
    content_en: 'Svante Pääbo achieved what seemed impossible: sequencing the complete genome of an extinct species. His team extracted DNA from 40,000-year-old Neanderthal bones, developing pioneering techniques to avoid contamination with modern human DNA. In 2010 they published the first draft of the Neanderthal genome. Comparison with modern human genomes revealed that non-Africans share 1-4% of their DNA with Neanderthals. Pääbo received the Nobel Prize in Medicine in 2022.',
    order: 0 },
  { id: 'sub-nean-2', entryId: 'entry-neanderthal-dna', title_es: 'Herencia funcional', title_en: 'Functional inheritance',
    content_es: 'El ADN neandertal tiene efectos funcionales en los humanos actuales. Algunas variantes heredadas son beneficiosas, como genes de inmunidad (TLR) que ayudan a combatir patógenos y genes de adaptación a climas fríos. Otras variantes son perjudiciales: aumentan el riesgo de depresión, diabetes tipo 2, lupus, enfermedad de Crohn y complicaciones graves por COVID-19. Curiosamente, ciertos genes neandertales relacionados con la queratina pueden haber sido útiles para adaptarse a ambientes fríos y secos fuera de África.',
    content_en: 'Neanderthal DNA has functional effects in modern humans. Some inherited variants are beneficial, such as immunity genes (TLR) that help fight pathogens and genes for cold climate adaptation. Other variants are detrimental: they increase risk of depression, type 2 diabetes, lupus, Crohn\'s disease, and severe COVID-19 complications. Interestingly, certain Neanderthal genes related to keratin may have been useful for adapting to cold and dry environments outside Africa.',
    order: 1 },
  { id: 'sub-aqua-1', entryId: 'entry-aquatic-ape', title_es: 'Características propuestas', title_en: 'Proposed characteristics',
    content_es: 'La hipótesis del mono acuático señala características humanas únicas entre los primates: bipedalismo eficiente en aguas someras, pérdida de vello corporal con retención de vello en la cabeza (como focas y nutrias), capa de grasa subcutánea (única entre primates, común en mamíferos acuáticos), control voluntario de la respiración, posición del orificio nasal hacia abajo, y el reflejo de inmersión que ralentiza el ritmo cardíaco al sumergirse.',
    content_en: 'The aquatic ape hypothesis points to unique human characteristics among primates: bipedalism efficient in shallow water, loss of body hair with retained head hair (like seals and otters), subcutaneous fat layer (unique among primates, common in aquatic mammals), voluntary breath control, downward-facing nostrils, and the diving reflex that slows heart rate when submerged.',
    order: 0 },
  { id: 'sub-aqua-2', entryId: 'entry-aquatic-ape', title_es: 'Críticas principales', title_en: 'Main criticisms',
    content_es: 'La comunidad paleoantropológica rechaza mayoritariamente la hipótesis. Las críticas incluyen: falta de evidencia fósil directa (no hay adaptaciones esqueléticas acuáticas como en mamíferos marinos); todas las características señaladas tienen explicaciones alternativas plausibles; no se ha identificado un período geológico específico para la fase acuática; y el registro fósil humano documenta una evolución en sabanas y bosques, no en costas. Se considera una hipótesis marginal con seguidores leales pero no aceptada científicamente.',
    content_en: 'The paleoanthropological community largely rejects the hypothesis. Criticisms include: lack of direct fossil evidence (no aquatic skeletal adaptations as in marine mammals); all cited characteristics have plausible alternative explanations; no specific geological period has been identified for the aquatic phase; and the human fossil record documents evolution in savannas and forests, not coasts. It is considered a marginal hypothesis with loyal followers but not scientifically accepted.',
    order: 1 },

  // === DOMAIN 12: SCIENCE - Physics ===
  { id: 'sub-quant-1', entryId: 'entry-quantum-mechanics', title_es: 'Dualidad onda-partícula', title_en: 'Wave-particle duality',
    content_es: 'La dualidad onda-partícula es uno de los conceptos más contraintuitivos de la mecánica cuántica. Dependiendo del experimento, la luz y la materia se comportan como ondas o como partículas. El experimento de la doble rendija demuestra que un electrón, disparado individualmente, crea un patrón de interferencia típico de ondas. Sin embargo, cuando se detecta qué rendija atraviesa, el patrón desaparece. La medición determina el comportamiento, sugiriendo un papel fundamental del observador en la realidad cuántica.',
    content_en: 'Wave-particle duality is one of the most counterintuitive concepts in quantum mechanics. Depending on the experiment, light and matter behave as waves or particles. The double-slit experiment demonstrates that a single electron, fired individually, creates an interference pattern typical of waves. However, when detecting which slit it passes through, the pattern disappears. Measurement determines behavior, suggesting a fundamental role of the observer in quantum reality.',
    order: 0 },
  { id: 'sub-quant-2', entryId: 'entry-quantum-mechanics', title_es: 'Interpretaciones', title_en: 'Interpretations',
    content_es: 'Existen múltiples interpretaciones de la mecánica cuántica. La interpretación de Copenhague postula que la función de onda colapsa al medir. La interpretación de muchos mundos (Hugh Everett) sostiene que todos los resultados posibles ocurren en universos paralelos. La interpretación de Bohm introduce variables ocultas no locales. La interpretación QBismo trata la mecánica cuántica como un modelo de las experiencias de agentes. No hay consenso sobre cuál es correcta, pero todas hacen las mismas predicciones experimentales.',
    content_en: 'Multiple interpretations of quantum mechanics exist. The Copenhagen interpretation postulates that the wave function collapses upon measurement. The many-worlds interpretation (Hugh Everett) holds that all possible outcomes occur in parallel universes. Bohm\'s interpretation introduces non-local hidden variables. QBism treats quantum mechanics as a model of agents\' experiences. There is no consensus on which is correct, but all make the same experimental predictions.',
    order: 1 },
  { id: 'sub-therm-1', entryId: 'entry-thermodynamics', title_es: 'Entropía y flecha del tiempo', title_en: 'Entropy and the arrow of time',
    content_es: 'La segunda ley de la termodinámica establece que la entropía total del universo siempre aumenta. Esto proporciona una dirección al tiempo: el pasado tiene menor entropía y el futuro mayor. El origen de esta asimetría temporal es una de las preguntas profundas de la física. Se relaciona con el Big Bang, que comenzó en un estado de baja entropía. Sin esta asimetría, procesos como la mezcla, la difusión y el envejecimiento no tendrían dirección preferida.',
    content_en: 'The second law of thermodynamics states that the total entropy of the universe always increases. This gives a direction to time: the past has lower entropy and the future higher. The origin of this temporal asymmetry is one of physics\' deep questions. It relates to the Big Bang, which began in a low entropy state. Without this asymmetry, processes like mixing, diffusion, and aging would have no preferred direction.',
    order: 0 },
  { id: 'sub-therm-2', entryId: 'entry-thermodynamics', title_es: 'Aplicaciones tecnológicas', title_en: 'Technological applications',
    content_es: 'Las leyes de la termodinámica son fundamentales para la ingeniería. Los motores térmicos (motores de combustión, turbinas de vapor) convierten calor en trabajo pero están limitados por la eficiencia de Carnot. Los refrigeradores y bombas de calor transfieren calor en dirección opuesta al flujo natural mediante trabajo externo. Las plantas de energía, desde las nucleares hasta las solares, están diseñadas según principios termodinámicos. La eficiencia energética máxima está limitada por estas leyes.',
    content_en: 'The laws of thermodynamics are fundamental to engineering. Heat engines (combustion engines, steam turbines) convert heat into work but are limited by Carnot efficiency. Refrigerators and heat pumps transfer heat opposite to natural flow through external work. Power plants, from nuclear to solar, are designed according to thermodynamic principles. Maximum energy efficiency is limited by these laws.',
    order: 1 },
  { id: 'sub-sm-1', entryId: 'entry-standard-model', title_es: 'Partículas y fuerzas', title_en: 'Particles and forces',
    content_es: 'El Modelo Estándar describe doce fermiones (seis quarks y seis leptones) que constituyen toda la materia conocida, y cinco bosones que median las fuerzas fundamentales. Los quarks (up, down, charm, strange, top, bottom) forman protones y neutrones. Los leptones incluyen el electrón, el muón, el tau y sus neutrinos. Las fuerzas son mediadas por fotones (electromagnetismo), gluones (fuerza nuclear fuerte), bosones W y Z (fuerza nuclear débil). El bosón de Higgs da masa a las partículas.',
    content_en: 'The Standard Model describes twelve fermions (six quarks and six leptons) constituting all known matter, and five bosons mediating fundamental forces. Quarks (up, down, charm, strange, top, bottom) form protons and neutrons. Leptons include the electron, muon, tau, and their neutrinos. Forces are mediated by photons (electromagnetism), gluons (strong nuclear force), W and Z bosons (weak nuclear force). The Higgs boson gives mass to particles.',
    order: 0 },
  { id: 'sub-sm-2', entryId: 'entry-standard-model', title_es: 'Más allá del modelo', title_en: 'Beyond the model',
    content_es: 'El Modelo Estándar, a pesar de su éxito, es incompleto. No incluye la gravedad, no explica la materia oscura ni la energía oscura, no resuelve la jerarquía de masas, y requiere 19 parámetros libres ajustados experimentalmente. La supersimetría propone compañeros superpesados para cada partícula conocida. La teoría de cuerdas postula que las partículas son modos de vibración de cuerdas unidimensionales. La gravedad cuántica de bucles cuantiza el espacio-tiempo mismo.',
    content_en: 'The Standard Model, despite its success, is incomplete. It does not include gravity, does not explain dark matter or dark energy, does not resolve the mass hierarchy, and requires 19 free parameters adjusted experimentally. Supersymmetry proposes superheavy partners for each known particle. String theory postulates particles are vibration modes of one-dimensional strings. Loop quantum gravity quantizes spacetime itself.',
    order: 1 },
  { id: 'sub-gr-1', entryId: 'entry-general-relativity', title_es: 'Agujeros negros', title_en: 'Black holes',
    content_es: 'Los agujeros negros son regiones del espacio-tiempo donde la gravedad es tan intensa que nada, ni siquiera la luz, puede escapar. Se forman cuando estrellas masivas colapsan al final de su vida. El horizonte de sucesos marca el punto sin retorno. En 2019, el Event Horizon Telescope capturó la primera imagen directa de un agujero negro (M87*), mostrando un anillo de luz brillante alrededor de una silueta oscura. Stephen Hawking propuso que los agujeros negros emiten radiación, evaporándose lentamente.',
    content_en: 'Black holes are regions of spacetime where gravity is so intense that nothing, not even light, can escape. They form when massive stars collapse at the end of their life. The event horizon marks the point of no return. In 2019, the Event Horizon Telescope captured the first direct image of a black hole (M87*), showing a bright ring of light around a dark silhouette. Stephen Hawking proposed that black holes emit radiation, slowly evaporating.',
    order: 0 },
  { id: 'sub-gr-2', entryId: 'entry-general-relativity', title_es: 'Ondas gravitacionales', title_en: 'Gravitational waves',
    content_es: 'Las ondas gravitacionales son perturbaciones en el espacio-tiempo que viajan a la velocidad de la luz, predichas por Einstein en 1916. Son producidas por eventos cósmicos violentos: fusión de agujeros negros, estrellas de neutrones, o explosiones de supernovas. El observatorio LIGO detectó ondas gravitacionales por primera vez en 2015, confirmando una predicción centenaria. Este descubrimiento abrió una nueva ventana al universo, permitiendo "escuchar" el cosmos además de observarlo.',
    content_en: 'Gravitational waves are disturbances in spacetime traveling at the speed of light, predicted by Einstein in 1916. They are produced by violent cosmic events: merging black holes, neutron stars, or supernova explosions. The LIGO observatory detected gravitational waves for the first time in 2015, confirming a century-old prediction. This discovery opened a new window to the universe, allowing us to "hear" the cosmos in addition to observing it.',
    order: 1 },

  // === DOMAIN 12: SCIENCE - Chemistry ===
  { id: 'sub-pt-1', entryId: 'entry-periodic-table', title_es: 'Predicciones de Mendeléyev', title_en: 'Mendeleev\'s predictions',
    content_es: 'Mendeléyev dejó espacios vacíos en su tabla original para elementos aún no descubiertos. Predijo con notable precisión las propiedades de tres de ellos: el eka-aluminio (descubierto como galio), el eka-boro (escandio) y el eka-silicio (germanio). Predijo sus masas atómicas, densidades, puntos de fusión y compuestos que formarían. Cuando estos elementos fueron descubiertos años después, las coincidencias fueron sorprendentes, validando su sistema periódico.',
    content_en: 'Mendeleev left empty spaces in his original table for yet-undiscovered elements. He predicted with remarkable accuracy the properties of three: eka-aluminum (discovered as gallium), eka-boron (scandium), and eka-silicon (germanium). He predicted their atomic masses, densities, melting points, and compounds they would form. When these elements were discovered years later, the coincidences were striking, validating his periodic system.',
    order: 0 },
  { id: 'sub-pt-2', entryId: 'entry-periodic-table', title_es: 'Evolución y tendencias', title_en: 'Evolution and trends',
    content_es: 'La tabla periódica ha evolucionado significativamente desde Mendeléyev. El descubrimiento de los gases nobles por Ramsay añadió un nuevo grupo. La comprensión de la estructura atómica por Moseley reorganizó la tabla por número atómico. Los elementos transuránicos (más pesados que el uranio) se han sintetido en laboratorios. La tabla muestra tendencias periódicas claras: radio atómico, electronegatividad, afinidad electrónica y energía de ionización varían sistemáticamente.',
    content_en: 'The periodic table has evolved significantly since Mendeleev. Ramsay\'s discovery of noble gases added a new group. Moseley\'s understanding of atomic structure reorganized the table by atomic number. Transuranic elements (heavier than uranium) have been synthesized in laboratories. The table shows clear periodic trends: atomic radius, electronegativity, electron affinity, and ionization energy vary systematically.',
    order: 1 },
  { id: 'sub-cb-1', entryId: 'entry-chemical-bonding', title_es: 'Enlace covalente', title_en: 'Covalent bonding',
    content_es: 'El enlace covalente se forma cuando dos átomos comparten pares de electrones. Puede ser simple (un par), doble (dos pares) o triple (tres pares). La molécula de nitrógeno (N₂) tiene un triple enlace, siendo una de las más estables. La polaridad del enlace depende de la diferencia de electronegatividad. Los enlaces covalentes pueden ser polares (distribución desigual de electrones) o apolares (distribución igual). Esta polaridad determina propiedades como la solubilidad y el punto de ebullición.',
    content_en: 'Covalent bonding forms when two atoms share electron pairs. It can be single (one pair), double (two pairs), or triple (three pairs). The nitrogen molecule (N₂) has a triple bond, being one of the most stable. Bond polarity depends on electronegativity difference. Covalent bonds can be polar (unequal electron distribution) or nonpolar (equal distribution). This polarity determines properties like solubility and boiling point.',
    order: 0 },
  { id: 'sub-cb-2', entryId: 'entry-chemical-bonding', title_es: 'Fuerzas intermoleculares', title_en: 'Intermolecular forces',
    content_es: 'Las fuerzas intermoleculares determinan las propiedades físicas de las sustancias. Las fuerzas de London (dispersión) son las más débiles, presentes en todas las moléculas. Las interacciones dipolo-dipolo ocurren entre moléculas polares. El enlace de hidrógeno es el más fuerte, ocurriendo entre un hidrógeno unido a N, O o F y un par solitario de otro átomo electronegativo. El agua debe sus propiedades únicas (alta tensión superficial, calor específico, densidad del hielo) al enlace de hidrógeno.',
    content_en: 'Intermolecular forces determine the physical properties of substances. London dispersion forces are the weakest, present in all molecules. Dipole-dipole interactions occur between polar molecules. Hydrogen bonding is the strongest, occurring between a hydrogen bonded to N, O, or F and a lone pair of another electronegative atom. Water owes its unique properties (high surface tension, specific heat, ice density) to hydrogen bonding.',
    order: 1 },
  { id: 'sub-org-1', entryId: 'entry-organic-chemistry', title_es: 'Hidrocarburos', title_en: 'Hydrocarbons',
    content_es: 'Los hidrocarburos son compuestos formados solo por carbono e hidrógeno. Se clasifican en alcanos (enlaces simples), alquenos (dobles enlaces), alquinos (triples enlaces) y aromáticos (anillos con enlaces conjugados). El petróleo y el gas natural son mezclas complejas de hidrocarburos. La isomería es fundamental en química orgánica: compuestos con la misma fórmula molecular pueden tener estructuras y propiedades radicalmente diferentes.',
    content_en: 'Hydrocarbons are compounds formed only by carbon and hydrogen. They are classified into alkanes (single bonds), alkenes (double bonds), alkynes (triple bonds), and aromatics (rings with conjugated bonds). Petroleum and natural gas are complex mixtures of hydrocarbons. Isomerism is fundamental in organic chemistry: compounds with the same molecular formula can have radically different structures and properties.',
    order: 0 },
  { id: 'sub-org-2', entryId: 'entry-organic-chemistry', title_es: 'Polímeros', title_en: 'Polymers',
    content_es: 'Los polímeros son macromoléculas formadas por la repetición de unidades más pequeñas llamadas monómeros. Pueden ser naturales (celulosa, proteínas, ADN) o sintéticos (polietileno, nailon, poliestireno). La polimerización puede ocurrir por adición (unión directa de monómeros) o condensación (liberación de una molécula pequeña). Los plásticos han transformado la sociedad moderna, pero su persistencia ambiental es un desafío global creciente.',
    content_en: 'Polymers are macromolecules formed by repetition of smaller units called monomers. They can be natural (cellulose, proteins, DNA) or synthetic (polyethylene, nylon, polystyrene). Polymerization can occur by addition (direct monomer bonding) or condensation (release of a small molecule). Plastics have transformed modern society, but their environmental persistence is a growing global challenge.',
    order: 1 },
  { id: 'sub-dna-1', entryId: 'entry-dna-structure', title_es: 'El código genético', title_en: 'The genetic code',
    content_es: 'El código genético es el conjunto de reglas que traduce la secuencia de nucleótidos del ADN en la secuencia de aminoácidos de las proteínas. Cada triplete de nucleótidos (codón) codifica un aminoácido específico. El código es casi universal (idéntico en bacterias, plantas y animales), lo que sugiere un origen común para toda la vida en la Tierra. De los 64 codones posibles, 61 codifican aminoácidos y 3 son señales de parada.',
    content_en: 'The genetic code is the set of rules translating the DNA nucleotide sequence into the amino acid sequence of proteins. Each nucleotide triplet (codon) encodes a specific amino acid. The code is nearly universal (identical in bacteria, plants, and animals), suggesting a common origin for all life on Earth. Of the 64 possible codons, 61 encode amino acids and 3 are stop signals.',
    order: 0 },
  { id: 'sub-dna-2', entryId: 'entry-dna-structure', title_es: 'Replicación y reparación', title_en: 'Replication and repair',
    content_es: 'La replicación del ADN es el proceso por el cual una molécula de ADN se duplica para producir dos moléculas hijas idénticas. Es semiconservativa: cada molécula hija contiene una hebra original y una nueva. La enzima ADN polimerasa añade nucleótidos complementarios. El proceso tiene una precisión asombrosa: errores de uno por cada mil millones de nucleótidos, gracias a mecanismos de corrección de pruebas y reparación. Cuando estos mecanismos fallan, se producen mutaciones, algunas beneficiosas, otras causantes de enfermedades.',
    content_en: 'DNA replication is the process by which a DNA molecule duplicates to produce two identical daughter molecules. It is semiconservative: each daughter molecule contains one original and one new strand. The enzyme DNA polymerase adds complementary nucleotides. The process has astonishing accuracy: errors of one per billion nucleotides, thanks to proofreading and repair mechanisms. When these mechanisms fail, mutations occur, some beneficial, others disease-causing.',
    order: 1 },

  // === DOMAIN 12: SCIENCE - Mathematics ===
  { id: 'sub-pyth-1', entryId: 'entry-pythagorean', title_es: 'Demostraciones clásicas', title_en: 'Classic proofs',
    content_es: 'Existen cientos de demostraciones del teorema de Pitágoras. Euclides dedicó el Libro I de sus Elementos a una demostración geométrica basada en áreas. La demostración china más antigua (c. 200 a.C.) usa un diagrama de descomposición de cuadrados. El presidente James Garfield publicó una demostración original en 1876 usando un trapecio. La demostración más simple visualmente consiste en reorganizar cuatro triángulos rectángulos idénticos dentro de un cuadrado mayor.',
    content_en: 'There are hundreds of proofs of the Pythagorean theorem. Euclid dedicated Book I of his Elements to a geometric proof based on areas. The oldest Chinese proof (c. 200 BC) uses a square decomposition diagram. President James Garfield published an original proof in 1876 using a trapezoid. The visually simplest proof involves rearranging four identical right triangles within a larger square.',
    order: 0 },
  { id: 'sub-pyth-2', entryId: 'entry-pythagorean', title_es: 'Aplicaciones modernas', title_en: 'Modern applications',
    content_es: 'El teorema de Pitágoras es esencial en innumerables aplicaciones modernas. En la navegación, permite calcular distancias entre coordenadas GPS. En el diseño de videojuegos y gráficos 3D, se usa para detectar colisiones y calcular distancias entre objetos. En la ingeniería, es fundamental para análisis estructurales. En estadística, la distancia euclidiana es una aplicación directa. La métrica pitagórica es la base de la geometría que usamos en la vida cotidiana.',
    content_en: 'The Pythagorean theorem is essential in countless modern applications. In navigation, it allows calculating distances between GPS coordinates. In video game design and 3D graphics, it is used for collision detection and distance calculation between objects. In engineering, it is fundamental for structural analysis. In statistics, Euclidean distance is a direct application. Pythagorean metric is the basis of geometry we use in everyday life.',
    order: 1 },
  { id: 'sub-calc-1', entryId: 'entry-calculus', title_es: 'Newton vs. Leibniz', title_en: 'Newton vs. Leibniz',
    content_es: 'El desarrollo independiente del cálculo por Newton y Leibniz generó una amarga disputa de prioridad. Newton desarrolló sus "fluxiones" en la década de 1660 pero no publicó hasta mucho después. Leibniz publicó su notación diferencial en 1684. La controversia dividió a la comunidad matemática europea durante décadas. Hoy se reconoce que ambos hicieron contribuciones fundamentales: Newton desde una perspectiva física y Leibniz desde una formalización algebraica. La notación de Leibniz es la que se usa universalmente.',
    content_en: 'The independent development of calculus by Newton and Leibniz generated a bitter priority dispute. Newton developed his "fluxions" in the 1660s but did not publish until much later. Leibniz published his differential notation in 1684. The controversy divided the European mathematical community for decades. Today both are recognized for fundamental contributions: Newton from a physical perspective and Leibniz from algebraic formalization. Leibniz\'s notation is universally used.',
    order: 0 },
  { id: 'sub-calc-2', entryId: 'entry-calculus', title_es: 'Ecuaciones diferenciales', title_en: 'Differential equations',
    content_es: 'Las ecuaciones diferenciales son ecuaciones que relacionan una función con sus derivadas. Describen casi todos los fenómenos del mundo real: el movimiento planetario (ecuaciones de Newton), la propagación del calor (ecuación de Fourier), las ondas sonoras (ecuación de onda), la mecánica cuántica (ecuación de Schrödinger), y la dinámica de poblaciones (ecuación logística). Resolver ecuaciones diferenciales es fundamental en física, ingeniería, biología, economía y ciencias sociales.',
    content_en: 'Differential equations are equations relating a function to its derivatives. They describe almost all real-world phenomena: planetary motion (Newton\'s equations), heat propagation (Fourier\'s equation), sound waves (wave equation), quantum mechanics (Schrödinger\'s equation), and population dynamics (logistic equation). Solving differential equations is fundamental in physics, engineering, biology, economics, and social sciences.',
    order: 1 },
  { id: 'sub-fib-1', entryId: 'entry-fibonacci', title_es: 'Fibonacci en la naturaleza', title_en: 'Fibonacci in nature',
    content_es: 'La sucesión de Fibonacci aparece en numerosos patrones naturales. La disposición de las semillas en el girasol sigue espirales de Fibonacci para optimizar el empaquetamiento. Las piñas muestran 8 espirales en una dirección y 13 en la otra. Las ramas de los árboles y las hojas de muchas plantas siguen la filotaxis de Fibonacci. Las conchas de caracoles y nautilos forman espirales logarítmicas relacionadas con la proporción áurea. Los huracanes y las galaxias espirales también exhiben este patrón.',
    content_en: 'The Fibonacci sequence appears in numerous natural patterns. The seed arrangement in sunflowers follows Fibonacci spirals to optimize packing. Pine cones show 8 spirals in one direction and 13 in the other. Tree branches and leaves of many plants follow Fibonacci phyllotaxis. Snail and nautilus shells form logarithmic spirals related to the golden ratio. Hurricanes and spiral galaxies also exhibit this pattern.',
    order: 0 },
  { id: 'sub-fib-2', entryId: 'entry-fibonacci', title_es: 'La proporción áurea', title_en: 'The golden ratio',
    content_es: 'La proporción áurea (φ ≈ 1.618) es un número irracional con propiedades matemáticas fascinantes. Dos cantidades están en proporción áurea si el cociente entre la suma y la mayor es igual al cociente entre la mayor y la menor. Aparece en el pentagrama regular, los rectángulos áureos y la espiral logarítmica. Se ha encontrado en el arte (El Partenón, Leonardo da Vinci), la arquitectura y la música, aunque algunas afirmaciones sobre su uso deliberado son exageradas o incorrectas.',
    content_en: 'The golden ratio (φ ≈ 1.618) is an irrational number with fascinating mathematical properties. Two quantities are in golden ratio if the ratio of their sum to the larger equals the ratio of the larger to the smaller. It appears in the regular pentagram, golden rectangles, and the logarithmic spiral. It has been found in art (the Parthenon, Leonardo da Vinci), architecture, and music, though some claims of its deliberate use are exaggerated or incorrect.',
    order: 1 },
  { id: 'sub-chaos-1', entryId: 'entry-chaos-theory', title_es: 'Efecto mariposa', title_en: 'Butterfly effect',
    content_es: 'El término "efecto mariposa" fue acuñado por Edward Lorenz en 1972 durante una conferencia titulada "¿Puede el batir de las alas de una mariposa en Brasil desatar un tornado en Texas?" Lorenz descubrió el efecto al ejecutar un modelo climático simplificado: redondeando una variable de 0.506127 a 0.506, obtuvo resultados radicalmente diferentes. Esto demuestra que en sistemas no lineales, pequeñas diferencias iniciales pueden amplificarse exponencialmente, haciendo impredecible el comportamiento a largo plazo.',
    content_en: 'The term "butterfly effect" was coined by Edward Lorenz in 1972 during a lecture titled "Can the flap of a butterfly\'s wings in Brazil set off a tornado in Texas?" Lorenz discovered the effect while running a simplified climate model: rounding a variable from 0.506127 to 0.506 produced radically different results. This demonstrates that in nonlinear systems, small initial differences can amplify exponentially, making long-term behavior unpredictable.',
    order: 0 },
  { id: 'sub-chaos-2', entryId: 'entry-chaos-theory', title_es: 'Sistemas complejos', title_en: 'Complex systems',
    content_es: 'La teoría del caos se ha extendido al estudio de sistemas complejos en todos los campos. En biología, los ritmos cardíacos y la dinámica neuronal pueden ser caóticos; la pérdida de caos puede indicar enfermedad. En economía, los mercados financieros muestran comportamiento caótico. En ecología, la dinámica de poblaciones depredador-presa puede ser caótica bajo ciertas condiciones. La teoría ha mostrado que el caos no es simplemente desorden, sino que puede contener patrones ocultos y orden subyacente.',
    content_en: 'Chaos theory has extended to the study of complex systems in all fields. In biology, heart rhythms and neural dynamics can be chaotic; loss of chaos may indicate disease. In economics, financial markets show chaotic behavior. In ecology, predator-prey population dynamics can be chaotic under certain conditions. The theory has shown that chaos is not simply disorder, but can contain hidden patterns and underlying order.',
    order: 1 },
]
